import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Home from './pages/Home';
import Login from './pages/Login'; 
import Signup from './pages/Signup'; 
import Dashboard from './pages/Dashboard';
import Navbar from './components/Navbar'; 
import Footer from './components/Footer'; 
import './App.css';

function App() {
  return (
    <Router>
      {/* १. Navbar जो वर स्थिर (Fixed/Sticky) राहील */}
      <Navbar />

      {/* २. मुख्य कंटेंट एरिया: 
          येथे 'paddingTop' दिला आहे जेणेकरून मजकूर नॅव्हबारच्या खाली दबणार नाही.
          'minHeight' मुळे फुटर नेहमी खाली राहील. */}
      <div className="main-content-wrapper" style={{ 
        minHeight: 'calc(100vh - 150px)', 
        paddingTop: '20px', 
        paddingBottom: '40px',
        backgroundColor: '#f8fafc' 
      }}>
        <div className="container">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/signup" element={<Signup />} />
            <Route path="/dashboard" element={<Dashboard />} />
            
            {/* जर युजरने चुकीची URL टाकली तर Home वर नेण्यासाठी (Optional) */}
            <Route path="*" element={<Home />} />
          </Routes>
        </div>
      </div>

      {/* ३. Footer जो सर्वात खाली असेल */}
      <Footer />
    </Router>
  );
}

export default App;
